// Register a new user
app.post('/users/register', (req, res) => {
  const { username, password, phone } = req.body;

  if (!username || !password || !phone) {
    return res.status(400).json({
      success: false,
      message: 'Username, password, and phone number are required.'
    });
  }

  // Validate phone number format (basic)
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  if (!phoneRegex.test(phone)) {
    return res.status(400).json({
      success: false,
      message: 'Phone number must be in E.164 format (e.g., +1234567890).'
    });
  }

  // Check if username already exists
  for (const [, user] of users) {
    if (user.username === username) {
      return res.status(409).json({
        success: false,
        message: 'Username already exists.'
      });
    }
  }

  const userId = `user_${crypto.randomUUID()}`;
  users.set(userId, {
    id: userId,
    username,
    password, // In production, hash this with bcrypt!
    phone
  });

  res.status(201).json({
    success: true,
    message: 'User registered successfully.',
    userId
  });
});

// First factor: Username/Password Login
app.post('/auth/login', (req, res) => {
  const { username, password } = req.body;

  if (!username || !password) {
    return res.status(400).json({
      success: false,
      message: 'Username and password are required.'
    });
  }

  // Find user by username
  let foundUser = null;
  for (const [, user] of users) {
    if (user.username === username && user.password === password) {
      foundUser = user;
      break;
    }
  }

  if (!foundUser) {
    return res.status(401).json({
      success: false,
      message: 'Invalid username or password.'
    });
  }

  // Set session for first factor
  req.session.userId = foundUser.id;
  req.session.firstFactorComplete = true;
  req.session.fullyAuthenticated = false;

  // Mask phone number for display
  const maskedPhone = foundUser.phone.replace(/(\+\d{1,3})\d+(\d{4})/, '$1****$2');

  res.json({
    success: true,
    message: 'First factor authentication successful. Please verify with SMS code.',
    maskedPhone,
    nextStep: 'POST /auth/send-code'
  });
});

// Send 2FA code via SMS
app.post('/auth/send-code', requireFirstFactor, rateLimiter, async (req, res) => {
  const userId = req.session.userId;
  const user = users.get(userId);

  if (!user) {
    return res.status(404).json({
      success: false,
      message: 'User not found.'
    });
  }

  // Check if there's an existing unexpired code
  const existingCode = twoFactorStore.get(userId);
  if (existingCode && (Date.now() - existingCode.createdAt) < 30000) {
    return res.status(429).json({
      success: false,
      message: 'A code was recently sent. Please wait 30 seconds before requesting a new one.',
      retryAfter: Math.ceil((30000 - (Date.now() - existingCode.createdAt)) / 1000)
    });
  }

  const code = generateCode();
  storeCode(userId, code);

  console.log(`[DEBUG] Generated code for user ${userId}: ${code}`);

  const smsResult = await sendSMS(user.phone, code);

  if (!smsResult.success) {
    // In development, still allow verification with the generated code
    console.warn('SMS sending failed, but code is stored for verification.');
    return res.json({
      success: true,
      message: 'Verification code generated. (SMS delivery may have failed - check logs in development)',
      // Remove the following line in production!
      devCode: process.env.NODE_ENV !== 'production' ? code : undefined
    });
  }

  const maskedPhone = user.phone.replace(/(\+\d{1,3})\d+(\d{4})/, '$1****$2');

  res.json({
    success: true,
    message: `Verification code sent to ${maskedPhone}.`,
    expiresIn: CODE_EXPIRATION_MS / 1000
  });
});

// Resend 2FA code
app.post('/auth/resend-code', requireFirstFactor, rateLimiter, async (req, res) => {
  const userId = req.session.userId;
  const user = users.get(userId);

  if (!user) {
    return res.status(404).json({
      success: false,
      message: 'User not found.'
    });
  }

  // Invalidate old code
  twoFactorStore.delete(userId);

  const code = generateCode();
  storeCode(userId, code);

  console.log(`[DEBUG] Resent code for user ${userId}: ${code}`);

  const smsResult = await sendSMS(user.phone, code);

  const maskedPhone = user.phone.replace(/(\+\d{1,3})\d+(\d{4})/, '$1****$2');

  res.json({
    success: true,
    message: `New verification code sent to ${maskedPhone}.`,
    expiresIn: CODE_EXPIRATION_MS / 1000,
    devCode: process.env.NODE_ENV !== 'production' ? code : undefined
  });
});

// Verify 2FA code
app.post('/auth/verify-code', requireFirstFactor, (req, res) => {
  const { code } = req.body;
  const userId = req.session.userId;

  if (!code) {
    return res.status(400).json({
      success: false,
      message: 'Verification code is required.'
    });
  }

  // Validate code format
  if (!/^\d{6}$/.test(code)) {
    return res.status(400).json({
      success: false,
      message: 'Invalid code format. Must be a 6-digit number.'
    });
  }

  const storedData = twoFactorStore.get(userId);

  if (!storedData) {
    return res.status(400).json({
      success: false,
      message: 'No verification code found. Please request a new code.'
    });
  }

  // Check if code has expired
  if (Date.now() - storedData.createdAt > CODE_EXPIRATION_MS) {
    twoFactorStore.delete(userId);
    return res.status(400).json({
      success: false,
      message: 'Verification code has expired. Please request a new code.'
    });
  }

  // Check max attempts
  if (storedData.attempts >= MAX_ATTEMPTS) {
    twoFactorStore.delete(userId);
    return res.status(429).json({
      success: false,
      message: 'Maximum verification attempts exceeded. Please request a new code.'
    });
  }

  // Increment attempts
  storedData.attempts += 1;

  // Use timing-safe comparison to prevent timing attacks
  const codeBuffer = Buffer.from(code.padEnd(6, '0'));
  const storedCodeBuffer = Buffer.from(storedData.code.padEnd(6, '0'));

  if (!crypto.timingSafeEqual(codeBuffer, storedCodeBuffer)) {
    const remainingAttempts = MAX_ATTEMPTS - storedData.attempts;
    return res.status(401).json({
      success: false,
      message: `Invalid verification code. ${remainingAttempts} attempt(s) remaining.`,
      remainingAttempts
    });
  }

  // Code is valid - mark as verified and complete 2FA
  storedData.verified = true;
  twoFactorStore.delete(userId);

  req.session.fullyAuthenticated = true;
  req.session.authenticatedAt = Date.now();

  const user = users.get(userId);

  res.json({
    success: true,
    message: 'Two-factor authentication successful. You are now fully authenticated.',
    user: {
      id: user.id,
      username: user.username
    }
  });
});

// Check authentication status
app.get('/auth/status', (req, res) => {
  const status = {
    authenticated: false,
    firstFactorComplete: false,
    fullyAuthenticated: false,
    userId: null
  };

  if (req.session.userId) {
    status.userId = req.session.userId;
    status.firstFactorComplete = !!req.session.firstFactorComplete;
    status.fullyAuthenticated = !!req.session.fullyAuthenticated;
    status.authenticated = status.fullyAuthenticated;

    if (status.fullyAuthenticated) {
      status.authenticatedAt = new Date(req.session.authenticatedAt).toISOString();
    }

    // Check if there's a pending 2FA code
    const storedData = twoFactorStore.get(req.session.userId);
    if (storedData && !storedData.verified) {
      status.pendingVerification = true;
      status.codeExpiresIn = Math.max(0, Math.ceil((CODE_EXPIRATION_MS - (Date.now() - storedData.createdAt)) / 1000));
      status.attemptsRemaining = MAX_ATTEMPTS - storedData.attempts;
    }
  }

  res.json(status);
});

// Logout
app.post('/auth/logout', (req, res) => {
  const userId = req.session.userId;

  if (userId) {
    twoFactorStore.delete(userId);
  }

  req.session.destroy((err) => {
    if (err) {
      return res.status(500).json({
        success: false,
        message: 'Failed to logout.'
      });
    }
    res.clearCookie('connect.sid');
    res.json({
      success: true,
      message: 'Logged out successfully.'
    });
  });
});

